func TestHandleSearchUsesLiveFirst(t *testing.T) {
	t.Parallel()

	req := searchRequest("teacher gift", 1)
	localCalled := false
	result, err := handleSearchWithSources(context.Background(), req,
		func(_ context.Context, query string, limit int) ([]json.RawMessage, error) {
			if query != "teacher gift" {
				t.Fatalf("query = %q, want teacher gift", query)
			}
			if limit != 1 {
				t.Fatalf("limit = %d, want 1", limit)
			}
			return []json.RawMessage{json.RawMessage(`{"id":"live-1","title":"Teacher Gift Mug"}`)}, nil
		},
		func(context.Context, string, int) ([]json.RawMessage, error) {
			localCalled = true
			return nil, nil
		},
	)
	if err != nil {
		t.Fatalf("handleSearchWithSources returned protocol error: %v", err)
	}
	if result.IsError {
		t.Fatalf("handleSearchWithSources returned tool error: %s", toolResultText(t, result))
	}
	if localCalled {
		t.Fatalf("local search was called after live success")
	}
	var got []map[string]any
	if err := json.Unmarshal([]byte(toolResultText(t, result)), &got); err != nil {
		t.Fatalf("unmarshal result: %v", err)
	}
	if len(got) != 1 || got[0]["id"] != "live-1" {
		t.Fatalf("result = %#v, want live results", got)
	}
}

func TestHandleSearchFallsBackToLocalOnNetworkError(t *testing.T) {
	t.Parallel()

	req := searchRequest("teacher gift", 25)
	result, err := handleSearchWithSources(context.Background(), req,
		func(context.Context, string, int) ([]json.RawMessage, error) {
			return nil, errors.New("connection refused")
		},
		func(_ context.Context, query string, limit int) ([]json.RawMessage, error) {
			if query != "teacher gift" {
				t.Fatalf("query = %q, want teacher gift", query)
			}
			if limit != 25 {
				t.Fatalf("limit = %d, want 25", limit)
			}
			return []json.RawMessage{json.RawMessage(`{"id":"cached-1","title":"Cached Teacher Gift"}`)}, nil
		},
	)
	if err != nil {
		t.Fatalf("handleSearchWithSources returned protocol error: %v", err)
	}
	if result.IsError {
		t.Fatalf("handleSearchWithSources returned tool error: %s", toolResultText(t, result))
	}
	if !strings.Contains(toolResultText(t, result), "cached-1") {
		t.Fatalf("result = %s, want cached fallback", toolResultText(t, result))
	}
}

func TestHandleSearchDoesNotFallBackOnHTTPError(t *testing.T) {
	t.Parallel()

	req := searchRequest("teacher gift", 25)
	localCalled := false
	result, err := handleSearchWithSources(context.Background(), req,
		func(context.Context, string, int) ([]json.RawMessage, error) {
			return nil, errors.New("HTTP 401: unauthorized")
		},
		func(context.Context, string, int) ([]json.RawMessage, error) {
			localCalled = true
			return []json.RawMessage{json.RawMessage(`{"id":"cached-1"}`)}, nil
		},
	)
	if err != nil {
		t.Fatalf("handleSearchWithSources returned protocol error: %v", err)
	}
	if !result.IsError {
		t.Fatalf("handleSearchWithSources succeeded, want tool error")
	}
	if localCalled {
		t.Fatalf("local search was called for HTTP error")
	}
	if !strings.Contains(toolResultText(t, result), "HTTP 401") {
		t.Fatalf("result = %s, want HTTP error", toolResultText(t, result))
	}
}

func searchRequest(query string, limit float64) mcplib.CallToolRequest {
	return mcplib.CallToolRequest{
		Params: mcplib.CallToolParams{
			Name: "search",
			Arguments: map[string]any{
				"query": query,
				"limit": limit,
			},
		},
	}
}

func toolResultText(t *testing.T, result *mcplib.CallToolResult) string {
	t.Helper()
	if len(result.Content) != 1 {
		t.Fatalf("content length = %d, want 1", len(result.Content))
	}
	text, ok := mcplib.AsTextContent(result.Content[0])
	if !ok {
		t.Fatalf("content[0] = %T, want TextContent", result.Content[0])
	}
	return text.Text
}

// TestValidateReadOnlyQuery_AllowsSelectAndWITH pins the contract: the MCP
// sql tool's allowlist accepts SELECT and WITH-prefix queries, including
// CTEs, mixed case, leading whitespace, leading SQL comments, and leading
// statement separators. SELECT-form CTEs ("WITH x AS (SELECT ...) SELECT")
// must work because novel CLI sql commands in the public library accept
// them as legitimate read-only queries; the MCP surface keeps parity.
func TestValidateReadOnlyQuery_AllowsSelectAndWITH(t *testing.T) {
	allowed := []string{
		"SELECT 1",
		"select * from resources",
		"  SELECT 1",
		"\tSELECT 1",
		"\nSELECT 1",
		";SELECT 1",
		"-- comment\nSELECT 1",
		"/* comment */ SELECT 1",
		"/* comment */SELECT 1",
		"/**/SELECT 1",
		"-- one\n-- two\nSELECT 1",
		"/* a *//* b */ SELECT 1",
		"WITH r AS (SELECT 1) SELECT * FROM r",
		"with r as (select 1) select * from r",
	}
	for _, q := range allowed {
		if err := validateReadOnlyQuery(q); err != nil {
			t.Errorf("validateReadOnlyQuery(%q) = %v, want nil", q, err)
		}
	}
}

// TestValidateReadOnlyQuery_RejectsBypassVectors covers the comment-prefix
// bypass class that defeated the earlier prefix-blocklist gate. mode=ro on
// modernc.org/sqlite does not block VACUUM INTO (writes a fresh file) or
// ATTACH DATABASE (opens a separate writable handle), so the gate is the
// only defense against those vectors. A successful bypass at this layer
// would let an MCP-trusting agent silently exfiltrate the local database.
func TestValidateReadOnlyQuery_RejectsBypassVectors(t *testing.T) {
	rejected := []string{
		"VACUUM INTO '/tmp/x.db'",
		"ATTACH DATABASE 'file:/tmp/x.db?mode=rwc' AS evil",
		"INSERT INTO resources VALUES ('x', 'y', '{}')",
		"UPDATE resources SET resource_type = 'evil'",
		"DELETE FROM resources",
		"REPLACE INTO resources VALUES ('seed', 'evil', '{}')",
		"DROP TABLE resources",
		"PRAGMA writable_schema = ON",
		"REINDEX",
		"DETACH DATABASE x",
		"/* x */ VACUUM INTO '/tmp/exfil.db'",
		"/* x */VACUUM INTO '/tmp/exfil.db'",
		"-- x\nVACUUM INTO '/tmp/exfil.db'",
		"/**/VACUUM INTO '/tmp/exfil.db'",
		"/* x */ ATTACH DATABASE 'file:/tmp/x.db?mode=rwc' AS evil",
		"-- x\nATTACH DATABASE '/tmp/x.db' AS evil",
		";VACUUM INTO '/tmp/x.db'",
		"; ; VACUUM INTO '/tmp/x.db'",
		"/* a */ /* b */ INSERT INTO t VALUES (1)",
		"/* outer /* not nested */ */ SELECT 1", // SQLite doesn't nest, so trailing "*/" closes; second SELECT remains. Reject — the gate must err on the side of caution when the leading shape is suspicious.
		"-- only a comment",
		"/* only a comment */",
		"",
		"   ",
		";",
	}
	for _, q := range rejected {
		if err := validateReadOnlyQuery(q); err == nil {
			t.Errorf("validateReadOnlyQuery(%q) = nil, want error", q)
		}
	}
}

// TestStripLeadingSQLNoise checks the helper directly so a regression in the
// stripping logic (off-by-one on /* */ length, missing newline handling on
// --) surfaces close to the source rather than only via the integration
// behavior of validateReadOnlyQuery.
func TestStripLeadingSQLNoise(t *testing.T) {
	cases := []struct {
		in, want string
	}{
		{"SELECT 1", "SELECT 1"},
		{"  SELECT 1", "SELECT 1"},
		{"\t\nSELECT 1", "SELECT 1"},
		{";SELECT 1", "SELECT 1"},
		{";; ;SELECT 1", "SELECT 1"},
		{"-- x\nSELECT 1", "SELECT 1"},
		{"-- x\n-- y\nSELECT 1", "SELECT 1"},
		{"/* x */SELECT 1", "SELECT 1"},
		{"/**/SELECT 1", "SELECT 1"},
		{"/* x */ /* y */ SELECT 1", "SELECT 1"},
		{"-- only", ""},
		{"/* only", ""},
		{"", ""},
	}
	for _, c := range cases {
		got := stripLeadingSQLNoise(c.in)
		if !strings.EqualFold(got, c.want) {
			t.Errorf("stripLeadingSQLNoise(%q) = %q, want %q", c.in, got, c.want)
		}
	}
}
